svg.script:

(function() {

  var DEFAULT_TITLE = "Savan Music";

  function applySettings() {
    try {
      var savedTitle = localStorage.getItem("savan_title");
      var savedIcon = localStorage.getItem("savan_icon");
      var savedLeave = localStorage.getItem("savan_leave");

      document.title = savedTitle && savedTitle.trim()
        ? savedTitle
        : DEFAULT_TITLE;

      var icon = document.querySelector("link[rel='icon']");
      if (!icon) {
        icon = document.createElement("link");
        icon.rel = "icon";
        document.head.appendChild(icon);
      }
      if (savedIcon && savedIcon.trim()) {
        icon.href = savedIcon;
      }

      window.onbeforeunload = savedLeave === "true" ? function(){ return true; } : null;

    } catch(e) {}
  }

  applySettings();

  window.addEventListener("storage", function(e) {
    if (e.key === "savan_title") {
      document.title = e.newValue && e.newValue.trim()
        ? e.newValue
        : DEFAULT_TITLE;
    }

    if (e.key === "savan_icon") {
      var icon = document.querySelector("link[rel='icon']");
      if (!icon) {
        icon = document.createElement("link");
        icon.rel = "icon";
        document.head.appendChild(icon);
      }
      if (e.newValue && e.newValue.trim()) {
        icon.href = e.newValue;
      }
    }

    if (e.key === "savan_leave") {
      window.onbeforeunload = e.newValue === "true"
        ? function(){ return true; }
        : null;
    }
  });

  // UPDATE THESE URLs to point to where your index.html is hosted
  // For example, if you host on GitHub Pages, use those URLs
  var URLS = [
    // Add your hosted URLs here, for example:
    // "https://raw.githack.com/yourusername/savan-music/main/index.html",
    // "https://cdn.jsdelivr.net/gh/yourusername/savan-music@latest/index.html",
  ];

  var frame = document.getElementById("f");

  // If no external URLs configured, load index.html from same directory
  if (URLS.length === 0) {
    // Try to load from relative path (works when SVG is opened locally alongside index.html)
    frame.src = "index.html";
  } else {
    function tryFetch(i) {
      if (i >= URLS.length) {
        // Fallback to local
        frame.src = "index.html";
        return;
      }

      fetch(URLS[i])
        .then(function(r) {
          if (!r.ok) throw new Error();
          return r.text();
        })
        .then(function(html) {
          var blob = new Blob([html], { type: "text/html" });
          frame.src = URL.createObjectURL(blob);
        })
        .catch(function() {
          tryFetch(i + 1);
        });
    }

    tryFetch(0);
  }

}());
